function createNode({
  type = 'method_declaration',
  fields = {},
}: {
  type?: string;
  fields?: Record<string, Parser.SyntaxNode | null | undefined>;
} = {}): Parser.SyntaxNode {
  return {
    type,
    childForFieldName(name: string) {
      return fields[name] ?? null;
    },
  } as unknown as Parser.SyntaxNode;
}

